var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"라이트닝──! 익스큐션──!!","JPN":"ライトニング───！　エクスキューージョン！！","ENG":"Lightning ──! Execution ──!","TWN":"雷光──！處刑──！！"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"흐음. 3종 침식체가 있다는 건 조금 의외였어.","JPN":"はは、第3種侵食体がいるのは予想外だったな。","ENG":"Hmpf, I didn’t expect to see a Category 3 C.O. here.","TWN":"嗯，有3類侵蝕體確實是有點意外。"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"자, 어때? 메이슨 씨?","JPN":"どうだ、メイソンさん？","ENG":"What do you say, Mr. Mason?","TWN":"不過梅森，如何？"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이렇게 짜릿한 볼거리까지 챙겨 주는 의뢰인은 자주 보기 힘들지 않나?","JPN":"こんなピリッとする見どころまで用意してくれる依頼主はそうそういないだろ？","ENG":"Your client does not just pay you well, but gives you an electrifying show as well!","TWN":"很少有像我這種委託人吧？可以讓你在一旁看熱鬧。"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……맨주먹만으로 저 많은 침식체를 혼자 쓸어 버리다니, 정말 괴물이 따로 없군.","JPN":"……素手であのおびただしい数の侵食体を一掃するとは、\\nどっちが化け物なんだか。","ENG":"You wiped out all those C.O.s with your bare hands. You really are a monster.","TWN":"……竟然可以一個人赤手空拳打倒那麼多侵蝕體，根本是怪物吧？"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"몇 번을 봐도 네가 같은 사람이란 게 믿기지가 않아.","JPN":"何度見ても、あんたが俺と同じ人間ってのが信じられないな。","ENG":"Every time I see you, I have trouble believing that you’re a human just like me.","TWN":"每次看到都覺得，平平都是人怎麼差這麼多？"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"나도 한때는 그렇게 생각했지만……","JPN":"俺も一時はそう思っていたが……","ENG":"I used to think like that...","TWN":"我也曾經這麼想過……"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그런 말이 어울릴 상대는 따로 있지. 안 그런가?","JPN":"その言葉にピッタリな奴は他にいるだろ？","ENG":"But now I know that such sentiments should be directed towards someone else. Don’t you agree?","TWN":"不過應該有人比我更像怪物吧？你說是不是？"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……리플레이서 퀸 말이군.","JPN":"……リプレイサー・クイーンのことか。","ENG":"You mean the Replacer Queen.","TWN":"……你是說克隆·女皇嗎？"},"stage":{"bg":"MAINSTREAM_5503010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"확실히 상식을 벗어난 힘이었어.","JPN":"たしかに常識外れな力だった。","ENG":"She was indeed extraordinary.","TWN":"確實是超出認知範圍的能力。"},"stage":{"bg":"MAINSTREAM_5503010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그리고 그 여자를 박살내버린 코핀 컴퍼니의 소대장도……","JPN":"そして、あの女を撃破したコフィンカンパニーの小隊長も……","ENG":"And so was the Commander from the Coffin Company who crushed her.","TWN":"更誇張的是那個把她打爆的科芬公司小隊長……"},"stage":{"bg":"MAINSTREAM_5503010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5503010","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그보다 CSE 레벨은 좀 어때?","JPN":"それよりCSEレベルはどうだ？","ENG":"How’s the CSE Level now?","TWN":"CSE等級現在如何？"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"틀렸어. 여전히 상승세야.","JPN":"ダメだな、依然として上昇し続けている。","ENG":"No good. It’s still rising.","TWN":"糟糕，還在持續上升中！"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"음? 침식체가 사라지면 상승세는 멈추는 거 아니었나?","JPN":"うん？　侵食体が消えれば上昇も止まるんじゃなかったか？","ENG":"Huh? I thought getting rid of the C.O.s would lower the level.","TWN":"怎麼會？侵蝕體消失後，照理說等級應該會下降才對？"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"다른 이유가 있다는 뜻이겠지.","JPN":"別の要因があるということだろう。","ENG":"Which means there must be some other reason for this phenomenon.","TWN":"一定是有原因的囉！"},"stage":{"bg":"HIGHWAY_DAYTIME","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};